def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            for a in range(1, int(capacity) + 1):
                if a % 2 == 0 and a < item:
                    score += np.exp(-a / capacity) * 12
            score += (1 - ratio) ** 4 * 18
        elif 0.2 <= ratio < 0.5:
            for b in range(1, 6):
                score += (np.cos(ratio * b * np.pi) ** 2) * b * 3
            if int(capacity) % 4 == 0:
                score += np.sqrt(ratio) * 10
            else:
                score += np.log1p(capacity) * ratio * 5
        elif 0.5 <= ratio <= 0.8:
            cumsum = 0
            for c in range(1, int(capacity // 2) + 1):
                if capacity % c == 0:
                    term = (ratio ** (c % 3)) * (np.sin(c * ratio * np.pi))
                    cumsum += term
            score += cumsum * 7 + np.tanh(ratio * 5) * 15
            if ratio > 0.65:
                for d in range(1, 4):
                    score += (d ** 2) / (ratio + d)
        elif 0.8 < ratio <= 1:
            for e in range(1, int(capacity) + 1):
                if e in [int(x) for x in np.linspace(1, capacity, 5)]:
                    score += np.log1p(e) * (1 - abs(ratio - e / capacity)) * 8
            score += np.exp(-10 * (1 - ratio) ** 2) * 25
        else:
            penalty = 0
            int_ratio = int(np.floor(ratio))
            for f in range(1, int_ratio + 2):
                if f == 0:
                    continue
                if int_ratio % f == 0:
                    penalty += f * (1 + np.sin(f + ratio))
                else:
                    penalty += (f / (int_ratio + 1)) * np.cos(ratio * f)
            penalty += np.sum([(((ratio % 1) ** k) * 2) for k in range(1, 5)])
            score = penalty * 12 + (ratio - 1) ** 3 * 30
            if ratio > 3:
                for g in range(1, int(capacity // 3) + 1):
                    if g == 0:
                        continue
                    score += np.sqrt(g) * np.tanh(ratio / (g + 0.5)) * 4
        if int(capacity) % 7 == 0 and ratio < 1:
            score *= 1.15
        elif int(capacity) % 11 == 0 and ratio > 1:
            score *= 0.85
        if 0.4 < ratio < 0.6 and capacity > 10:
            extra = 0
            for h in range(1, 5):
                extra += np.log1p(h * ratio) * h
            score += extra
        priorities[i] = score
    finite_mask = np.isfinite(priorities)
    if not np.any(finite_mask):
        return np.full_like(priorities, 1000)
    min_priority = np.min(priorities[finite_mask])
    priorities = np.where(finite_mask, priorities, min_priority + 250)
    return priorities
